<template>
  <div class="container-fluid p-0">
    <div class="row">
      <div class="col-12">
        <div class="card shadow-sm">
          <div class="card-header bg-white py-3">
            <h5 class="card-title mb-0 fw-bold">Pengaturan Kontak</h5>
          </div>
          <div class="card-body">
            <div v-if="isLoadingFetch" class="text-center py-5">
              <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
              </div>
              <p class="mt-2 text-muted">Memuat data...</p>
            </div>

            <form v-else @submit.prevent="submitForm">
              
              <h6 class="fw-bold mb-3 border-bottom pb-2">Informasi Utama</h6>
              <div class="row">
                <div class="col-md-6 mb-3">
                  <label class="form-label fw-semibold">Nama Instansi </label>
                  <input
                    type="text"
                    class="form-control"
                    v-model="formData.namainstansi"
                    :class="{ 'is-invalid': formErrors.namainstansi }"
                    placeholder="Contoh: Dinas Kominfo"
                  />
                  <div class="invalid-feedback">{{ formErrors.namainstansi }}</div>
                </div>
                
                <div class="col-md-6 mb-3">
                  <label class="form-label fw-semibold">Email Resmi </label>
                  <input
                    type="email"
                    class="form-control"
                    v-model="formData.email"
                    :class="{ 'is-invalid': formErrors.email }"
                    placeholder="email@instansi.go.id"
                  />
                  <div class="invalid-feedback">{{ formErrors.email }}</div>
                </div>

                <div class="col-12 mb-3">
                  <label class="form-label fw-semibold">Alamat Lengkap</label>
                  <textarea
                    class="form-control"
                    v-model="formData.alamatinstansi"
                    :class="{ 'is-invalid': formErrors.alamatinstansi }"
                    rows="3"
                    placeholder="Masukkan alamat lengkap instansi"
                  ></textarea>
                  <div class="invalid-feedback">{{ formErrors.alamatinstansi }}</div>
                </div>
              </div>

              <h6 class="fw-bold mb-3 mt-4 border-bottom pb-2">Kontak</h6>
              <div class="row">
                <div class="col-md-6 mb-3">
                  <label class="form-label fw-semibold">Nomor Telepon</label>
                  <div class="input-group">
                    <span class="input-group-text"><i class="fa-solid fa-phone"></i></span>
                    <input
                        type="text"
                        class="form-control"
                        v-model="formData.telepone"
                        :class="{ 'is-invalid': formErrors.telepone }"
                        placeholder="021-xxxxxx"
                    />
                  </div>
                  <div class="invalid-feedback">{{ formErrors.telepone }}</div>
                </div>
                <div class="col-md-6 mb-3">
                  <label class="form-label fw-semibold">WhatsApp</label>
                  <div class="input-group">
                    <span class="input-group-text"><i class="fa-brands fa-whatsapp"></i></span>
                    <input
                        type="text"
                        class="form-control"
                        v-model="formData.whatsapp"
                        :class="{ 'is-invalid': formErrors.whatsapp }"
                        placeholder="628xxxxxxxx"
                    />
                  </div>
                  <div class="invalid-feedback">{{ formErrors.whatsapp }}</div>
                </div>
              </div>

              <h6 class="fw-bold mb-3 mt-4 border-bottom pb-2">Media Sosial (Link/Username)</h6>
              <div class="row">
                <div class="col-md-6 mb-3">
                  <label class="form-label fw-semibold">Instagram</label>
                  <div class="input-group">
                    <span class="input-group-text"><i class="fa-brands fa-instagram"></i></span>
                    <input type="text" class="form-control" v-model="formData.instagram" placeholder="Link profil Instagram">
                  </div>
                </div>
                <div class="col-md-6 mb-3">
                  <label class="form-label fw-semibold">Facebook</label>
                  <div class="input-group">
                    <span class="input-group-text"><i class="fa-brands fa-facebook"></i></span>
                    <input type="text" class="form-control" v-model="formData.facebook" placeholder="Link halaman Facebook">
                  </div>
                </div>
                <div class="col-md-6 mb-3">
                  <label class="form-label fw-semibold">Twitter (X)</label>
                  <div class="input-group">
                    <span class="input-group-text"><i class="fa-brands fa-twitter"></i></span>
                    <input type="text" class="form-control" v-model="formData.twitter" placeholder="Link profil Twitter">
                  </div>
                </div>
                <div class="col-md-6 mb-3">
                  <label class="form-label fw-semibold">TikTok</label>
                  <div class="input-group">
                    <span class="input-group-text"><i class="fa-brands fa-tiktok"></i></span>
                    <input type="text" class="form-control" v-model="formData.tiktok" placeholder="Link profil TikTok">
                  </div>
                </div>
                <div class="col-md-12 mb-3">
                  <label class="form-label fw-semibold">YouTube</label>
                  <div class="input-group">
                    <span class="input-group-text"><i class="fa-brands fa-youtube"></i></span>
                    <input type="text" class="form-control" v-model="formData.youtube" placeholder="Link channel YouTube">
                  </div>
                </div>
              </div>

              <div v-if="errorMessage" class="alert alert-danger mt-3">
                {{ errorMessage }}
              </div>

              <div class="d-flex justify-content-end gap-2 mt-4 pt-3 border-top">
                <button type="button" class="btn btn-secondary" @click="resetForm">
                  Reset
                </button>
                <button type="submit" class="btn btn-primary" :disabled="isSubmitting">
                  <span v-if="isSubmitting" class="spinner-border spinner-border-sm me-1"></span>
                  Simpan Perubahan
                </button>
              </div>
            </form>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup>
import { reactive, ref, onMounted } from "vue";
import { useToast } from "vue-toastification";
import * as yup from "yup";
import Swal from "sweetalert2";
import { getDetailApplication, updateApplication } from "@/services/general/website/settings/applications";

const toast = useToast();

// === State ===
const isLoadingFetch = ref(true);
const isSubmitting = ref(false);
const errorMessage = ref(null);

const DEFAULT_APP_ID = "46efe2ad-8336-422f-9b1b-6944e3d3802b";

const formData = reactive({
  idaplikasi: "",
  namainstansi: "",
  alamatinstansi: "",
  email: "",
  telepone: "",
  whatsapp: "",
  instagram: "",
  facebook: "",
  twitter: "",
  tiktok: "",
  youtube: "",
});

const formErrors = reactive({});

// === Skema Validasi ===
const validationSchema = yup.object().shape({
  namainstansi: yup.string().nullable(),
  email: yup.string().email("Format email tidak valid").nullable(),
  alamatinstansi: yup.string().nullable(),
  telepone: yup.string().nullable(),
  whatsapp: yup.string().nullable(),
  instagram: yup.string().nullable(),
  facebook: yup.string().nullable(),
  twitter: yup.string().nullable(),
  tiktok: yup.string().nullable(),
  youtube: yup.string().nullable(),
});

// === Lifecycle Hooks ===
onMounted(() => {
  fetchData();
});

// === Methods ===
async function fetchData() {
  isLoadingFetch.value = true;
  try {
    const response = await getDetailApplication(DEFAULT_APP_ID);
    const rawData = response.data ? response.data : response;
    let sourceData = null;

    if (Array.isArray(rawData) && rawData.length > 0) {
        if (rawData[0].data && Array.isArray(rawData[0].data)) {
            sourceData = rawData[0].data[0]; 
        } 
        else {
            sourceData = rawData[0];
        }
    } else if (rawData?.data && Array.isArray(rawData.data)) {
        sourceData = rawData.data[0];
    } else if (rawData?.record) {
        sourceData = rawData.record;
    } else {
        sourceData = rawData;
    }

    if (sourceData) {
        formData.idaplikasi = sourceData.idaplikasi || DEFAULT_APP_ID;

        formData.namainstansi = sourceData.namainstansi || "";
        formData.alamatinstansi = sourceData.alamatinstansi || "";
        formData.email = sourceData.email || "";
        formData.telepone = sourceData.telepone || "";
        formData.whatsapp = sourceData.whatsapp || "";
        formData.instagram = sourceData.instagram || "";
        formData.facebook = sourceData.facebook || "";
        formData.twitter = sourceData.twitter || "";
        formData.tiktok = sourceData.tiktok || "";
        formData.youtube = sourceData.youtube || "";
    }

  } catch (error) {
    console.error("Error fetching data:", error);
    if(error.response && error.response.status !== 404) {
        toast.error("Gagal memuat data kontak");
    }
  } finally {
    isLoadingFetch.value = false;
  }
}

function handleError(error) {
  errorMessage.value =
    error.response?.data?.failed ||
    error.response?.data?.message ||
    "Gagal menyimpan data. Silakan coba lagi.";
  toast.error(errorMessage.value);
}

async function validateForm() {
  Object.keys(formErrors).forEach((key) => delete formErrors[key]);
  try {
    await validationSchema.validate(formData, { abortEarly: false });
    return true;
  } catch (err) {
    err.inner.forEach((e) => {
      formErrors[e.path] = e.message;
    });
    toast.warning("Mohon periksa kembali isian form");
    return false;
  }
}

function resetForm() {
  Swal.fire({
    title: 'Reset Data',
    text: "Apakah Anda yakin ingin mengembalikan data ke kondisi awal? Perubahan yang belum disimpan akan hilang.",
    icon: "warning",
    showCancelButton: true,
    confirmButtonText: '<i class="fa fa-undo me-2"></i> Reset', 
    cancelButtonText: '<i class="fa fa-times me-2"></i> Batal',
    cancelButtonColor: "#efefef",
    confirmButtonColor: "#d33",
    reverseButtons: true,
  }).then((result) => {
    if (result.isConfirmed) {
      formData.namainstansi = "";
      formData.alamatinstansi = "";
      formData.email = "";
      formData.telepone = "";
      formData.whatsapp = "";
      formData.instagram = "";
      formData.facebook = "";
      formData.twitter = "";
      formData.tiktok = "";
      formData.youtube = "";

      Object.keys(formErrors).forEach((key) => delete formErrors[key]);
      
      toast.info("Form telah dikosongkan");
    }
  });
}

async function submitForm() {
  const isValid = await validateForm();
  if (!isValid) return;

  isSubmitting.value = true;
  errorMessage.value = null;

  const data = new FormData();
  data.append("record[namainstansi]", formData.namainstansi || "");
  data.append("record[alamatinstansi]", formData.alamatinstansi || "");
  data.append("record[email]", formData.email || "");
  data.append("record[telepone]", formData.telepone || "");
  data.append("record[whatsapp]", formData.whatsapp || "");
  data.append("record[instagram]", formData.instagram || "");
  data.append("record[facebook]", formData.facebook || "");
  data.append("record[twitter]", formData.twitter || "");
  data.append("record[tiktok]", formData.tiktok || "");
  data.append("record[youtube]", formData.youtube || "");

  data.append("_method", "PUT");

  try {
    const idToUpdate = formData.idaplikasi || DEFAULT_APP_ID;
    await updateApplication(idToUpdate, data);
    toast.success("Data kontak berhasil diperbarui");
    await fetchData(); 
  } catch (error) {
    handleError(error);
  } finally {
    isSubmitting.value = false;
  }
}
</script>

<style scoped>
.invalid-feedback {
  display: block;
  font-size: 0.875em;
}
</style>