<template>
  <BaseTable
    title="Daftar Pengguna"
    entityName="Pengguna" 
    :apiService="userApi"
    :FormModalComponent="UserFormModal"
    :columns="columns"
    primaryKey="idpengguna"
    deleteItemNameKey="nama"
    :initialFilters="initialFilters"
    initialSortColumn="nama"
    initialSortDirection="asc"
  >
    <template #filters="{ filters }">
      <div class="row g-3">
        <div class="col-md-3">
          <label for="filterUserName" class="form-label text-dark fw-semibold">Nama Pengguna</label>
          <input
            type="text"
            id="filterUserName"
            class="form-control"
            v-model="filters.nama"
            placeholder="Masukkan nama pengguna"
          />
        </div>
        <div class="col-md-3">
          <label for="filterUserEmail" class="form-label text-dark fw-semibold">Email</label>
          <input
            type="text"
            id="filterUserEmail"
            class="form-control"
            v-model="filters.email"
            placeholder="Masukkan email"
          />
        </div>
        <div class="col-md-3">
          <label for="filterUserLevel" class="form-label text-dark fw-semibold">Level</label>
          <input
            type="text"
            id="filterUserLevel"
            class="form-control"
            v-model="filters.namalevel"
            placeholder="Masukkan level"
          />
        </div>
        <div class="col-md-3">
          <label for="filterUserVocational" class="form-label text-dark fw-semibold">Kejuruan</label>
          <input
            type="text"
            id="filterUserVocational"
            class="form-control"
            v-model="filters.namakejuruan"
            placeholder="Masukkan nama kejuruan"
          />
        </div>
      </div>
    </template>

    <template #cell(namalevel)="{ item }">
      {{ item.roles?.namalevel || '-' }}
    </template>
    
    <template #cell(namakejuruan)="{ item }">
      {{ item['vocational-fields']?.namakejuruan || '-' }}
    </template>

  </BaseTable>
</template>

<script setup>
import { defineAsyncComponent } from 'vue';
import BaseTable from '@/components/base/BaseTable.vue';
import { deleteUser, getUsers } from '@/services/referensi/users';

const UserFormModal = defineAsyncComponent(() => 
  import('./UserFormModal.vue') 
);

const userApi = {
  get: getUsers,
  delete: deleteUser,
};

// Kolom untuk tabel Pengguna
const columns = [
  { key: 'nama', label: 'Nama', sortable: true },
  { key: 'email', label: 'Email', sortable: true },
  { key: 'telp', label: 'Telepon', sortable: false },
  // Kolom 'namalevel' berasal dari relasi 'roles'
  { key: 'namalevel', label: 'Level', sortable: true }, 
  // Kolom 'namakejuruan' berasal dari relasi 'vocational-fields'
  { key: 'namakejuruan', label: 'Kejuruan', sortable: true },
  { key: 'lastlogin', label: 'Login Terakhir', sortable: true },
];

// Filter untuk pencarian data Pengguna
const initialFilters = {
  nama: "",
  email: "",
  namalevel: "",
  namakejuruan: "",
};
</script>